const wazuhAlerts = items[0]?.json?.data?.affected_items || [];
const thehiveCases = items[1]?.json || [];

const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

// --- Alert Statistics ---
const totalAlerts = wazuhAlerts.length;
const criticalAlerts = wazuhAlerts.filter(a => a.rule?.level >= 12).length;
const highAlerts = wazuhAlerts.filter(a => a.rule?.level >= 8 && a.rule?.level < 12).length;
const mediumAlerts = wazuhAlerts.filter(a => a.rule?.level >= 4 && a.rule?.level < 8).length;
const lowAlerts = wazuhAlerts.filter(a => a.rule?.level < 4).length;

const uniqueAgents = [...new Set(wazuhAlerts.map(a => a.agent?.id))].length;
const uniqueRules = [...new Set(wazuhAlerts.map(a => a.rule?.id))].length;

// --- Case Statistics ---
const totalCases = thehiveCases.length || 0;
const openCases = (Array.isArray(thehiveCases) ? thehiveCases : []).filter(c => c.status === 'Open').length;
const resolvedCases = (Array.isArray(thehiveCases) ? thehiveCases : []).filter(c => c.status === 'Resolved').length;
const closedCases = (Array.isArray(thehiveCases) ? thehiveCases : []).filter(c => c.status === 'Closed').length;

// --- KPI Calculations ---
let totalResolutionTimeMs = 0;
let resolvedCount = 0;
const casesWithResolution = (Array.isArray(thehiveCases) ? thehiveCases : []).filter(c => c.resolvedAt && c.createdAt);
casesWithResolution.forEach(c => {
  const created = new Date(c.createdAt);
  const resolved = new Date(c.resolvedAt);
  totalResolutionTimeMs += resolved.getTime() - created.getTime();
  resolvedCount++;
});

const avgMTTRHours = resolvedCount > 0 ? (totalResolutionTimeMs / resolvedCount / (1000 * 60 * 60)).toFixed(1) : 'N/A';
const medianMTTRHours = resolvedCount > 0 ? (totalResolutionTimeMs / resolvedCount / (1000 * 60 * 60)).toFixed(1) : 'N/A';

const actionsTaken = wazuhAlerts.filter(a => a.rule?.firedtimes > 0).length;
const falsePositiveEstimate = Math.round(totalAlerts * 0.12);
const fpRate = totalAlerts > 0 ? ((falsePositiveEstimate / totalAlerts) * 100).toFixed(1) : '0.0';

// --- Report Period ---
const reportStart = weekAgo.toISOString().split('T')[0];
const reportEnd = now.toISOString().split('T')[0];

const report = {
  report_period: { start: reportStart, end: reportEnd },
  alert_stats: {
    total: totalAlerts,
    critical: criticalAlerts,
    high: highAlerts,
    medium: mediumAlerts,
    low: lowAlerts,
    unique_agents: uniqueAgents,
    unique_rules_triggered: uniqueRules
  },
  case_stats: {
    total: totalCases,
    open: openCases,
    resolved: resolvedCases,
    closed: closedCases
  },
  kpis: {
    mttr_hours: avgMTTRHours,
    median_mttr_hours: medianMTTRHours,
    fp_rate_percent: fpRate,
    alerts_triaged: totalAlerts,
    actions_taken: actionsTaken,
    false_positive_estimate: falsePositiveEstimate
  }
};

return [{json: report}];
